import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface HourlyIntake {
  hour: string;
  amount: number;
}

interface HydrationData {
  dailyGoal: {
    target: number;
    current: number;
    percentage: number;
  };
  hourlyIntake: HourlyIntake[];
}

export default function Widget() {
  const hydrationData = response.data as HydrationData;
  const { dailyGoal, hourlyIntake } = hydrationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#00BCD4' }}>
              Hydration Tracker
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {dailyGoal.current} ml
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of {dailyGoal.target} ml goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#00BCD4' }}>
                {dailyGoal.percentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E0F7FA',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#00BCD4',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: hourlyIntake.map(d => d.amount),
                color: '#00BCD4',
              },
            ]}
            xAxis={[
              {
                data: hourlyIntake.map(d => d.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
